## Conclusion

This application requires **significant hardening** before production deployment. The combination of unauthenticated access to PII, missing input validation, absent error handling, and lack of security headers creates multiple attack vectors. Prioritize Phase 1 fixes immediately.

**Risk Level: CRITICAL** ⚠️

// Production-ready Express application with security and error handling
// This is an improved version addressing all critical issues

require('dotenv').config();
const express = require('express');
const helmet = require('helmet');
const cors = require('cors');
const morgan = require('morgan');
const { query, validationResult } = require('express-validator');
const rateLimit = require('express-rate-limit');
const crypto = require('crypto');

const app = express();
const PORT = process.env.PORT || 3000;
const NODE_ENV = process.env.NODE_ENV || 'development';

// ============================================================================
// SECURITY MIDDLEWARE
// ============================================================================

// Add security headers
app.use(helmet());

// Configure CORS
app.use(cors({
  origin: process.env.ALLOWED_ORIGINS?.split(',') || ['http://localhost:3000'],
  credentials: true,
  methods: ['GET', 'POST', 'PUT', 'DELETE', 'OPTIONS'],
  allowedHeaders: ['Content-Type', 'Authorization']
}));

// Request logging
app.use(morgan(NODE_ENV === 'production' ? 'combined' : 'dev'));

// ============================================================================
// PARSING & BODY MIDDLEWARE
// ============================================================================

// Parse JSON and URL-encoded bodies with size limits
app.use(express.json({ limit: '10mb' }));
app.use(express.urlencoded({ extended: true, limit: '10mb' }));

// ============================================================================
// REQUEST TRACKING & CORRELATION
// ============================================================================

app.use((req, res, next) => {
  // Add request ID for logging and tracking
  req.id = req.headers['x-request-id'] || crypto.randomUUID();
  res.setHeader('X-Request-ID', req.id);
  next();
});

// ============================================================================
// RATE LIMITING
// ============================================================================

const apiLimiter = rateLimit({
  windowMs: 15 * 60 * 1000, // 15 minutes
  max: process.env.RATE_LIMIT_MAX || 100, // limit each IP to 100 requests per windowMs
  message: 'Too many requests from this IP, please try again later.',
  standardHeaders: true, // Return rate limit info in the `RateLimit-*` headers
  legacyHeaders: false, // Disable the `X-RateLimit-*` headers
  skip: () => NODE_ENV === 'development' // Skip rate limiting in development
});

app.use('/api/', apiLimiter);

// ============================================================================
// ROUTES WITH INPUT VALIDATION & ERROR HANDLING
// ============================================================================

// Health check endpoint (no auth required, minimal data exposure)
app.get('/health', (req, res) => {
  try {
    res.json({
      status: 'ok',
      service: 'app',
      uptime: process.uptime(),
      environment: NODE_ENV
      // Note: Removed timestamp to reduce information disclosure
    });
  } catch (error) {
    res.status(500).json({
      status: 'error',
      message: 'Health check failed',
      requestId: req.id
    });
  }
});

// Protected users endpoint with validation and authentication
app.get('/api/v1/users',
  // Middleware: Validate query parameters
  query('limit')
    .optional()
    .isInt({ min: 1, max: 100 })
    .withMessage('limit must be between 1 and 100'),
  query('offset')
    .optional()
    .isInt({ min: 0 })
    .withMessage('offset must be 0 or greater'),

  // Middleware: Check authentication (simplified example)
  (req, res, next) => {
    const authHeader = req.headers.authorization;
    if (!authHeader || !authHeader.startsWith('Bearer ')) {
      return res.status(401).json({
        error: 'Unauthorized',
        message: 'Missing or invalid authentication token',
        requestId: req.id
      });
    }
    // In production, verify JWT token here
    req.user = { id: 1, role: 'user' };
    next();
  },

  // Route handler with error handling
  (req, res, next) => {
    try {
      // Check for validation errors
      const errors = validationResult(req);
      if (!errors.isEmpty()) {
        return res.status(400).json({
          error: 'Validation Error',
          details: errors.array(),
          requestId: req.id
        });
      }

      const limit = Math.min(parseInt(req.query.limit) || 10, 100);
      const offset = parseInt(req.query.offset) || 0;

      // Example mock data - in production, fetch from database
      const allUsers = [
        { id: 1, name: 'Alice', email: 'alice@example.com', createdAt: new Date().toISOString() },
        { id: 2, name: 'Bob', email: 'bob@example.com', createdAt: new Date().toISOString() }
      ];

      // Apply pagination
      const users = allUsers.slice(offset, offset + limit);

      // Return paginated response
      res.json({
        data: users,
        pagination: {
          limit,
          offset,
          total: allUsers.length
        },
        requestId: req.id
      });
    } catch (error) {
      next(error); // Pass to error handler
    }
  }
);

// ============================================================================
// 404 HANDLER
// ============================================================================

app.use((req, res) => {
  res.status(404).json({
    error: 'Not Found',
    message: `The requested endpoint ${req.method} ${req.path} does not exist`,
    requestId: req.id,
    availableEndpoints: [
      'GET /health',
      'GET /api/v1/users'
    ]
  });
});

// ============================================================================
// GLOBAL ERROR HANDLER
// ============================================================================

app.use((err, req, res, next) => {
  const status = err.status || err.statusCode || 500;

  // Log error details (in production, use structured logging)
  console.error({
    requestId: req.id,
    status,
    message: err.message,
    stack: NODE_ENV !== 'production' ? err.stack : undefined
  });

  // In production, hide error details from client
  const clientMessage = NODE_ENV === 'production'
    ? 'Internal Server Error'
    : err.message;

  res.status(status).json({
    error: 'Server Error',
    message: clientMessage,
    requestId: req.id
    // Note: Stack trace intentionally hidden from clients
  });
});

// ============================================================================
// UNHANDLED EXCEPTION & REJECTION HANDLERS
// ============================================================================

process.on('unhandledRejection', (reason, promise) => {
  console.error('Unhandled Rejection at:', promise, 'reason:', reason);
  // In production, log to error tracking service (Sentry, DataDog, etc.)
});

process.on('uncaughtException', (error) => {
  console.error('Uncaught Exception:', error);
  // In production, log to error tracking service
  // Gracefully shutdown after logging
  process.exit(1);
});

// ============================================================================
// SERVER STARTUP & GRACEFUL SHUTDOWN
// ============================================================================

let server;

server = app.listen(PORT, () => {
  console.log(`Server running on port ${PORT} (${NODE_ENV} environment)`);
});

// Graceful shutdown
process.on('SIGTERM', () => {
  console.log('SIGTERM received, shutting down gracefully...');
  server.close(() => {
    console.log('Server closed. Process exiting.');
    process.exit(0);
  });
});

process.on('SIGINT', () => {
  console.log('SIGINT received, shutting down gracefully...');
  server.close(() => {
    console.log('Server closed. Process exiting.');
    process.exit(0);
  });
});

// Timeout for graceful shutdown (30 seconds)
setTimeout(() => {
  console.error('Forced shutdown - graceful shutdown timeout exceeded');
  process.exit(1);
}, 30000);

module.exports = app;

